INSERT INTO public.wiki_pages (id, room_id, title, content, parent_id, created_at, updated_at) VALUES ('f41572f1-546a-4ba8-b36d-af28aec019e2', 'c3497459-c4bf-4a9e-a01e-032f1a3f4df0', 'Thæia, Gaia & Hæphistos', '<p>En los albores del Tiempo, cuando la existencia misma aún estaba en gestación, Thæia, la Diosa del Sol y la Brillantez dió origen a la Creación. A través de la manifestación de la Primera Llama, iluminó los confines del universo, trayendo luz y vida a todo lo que tocaba. Thæia observó la vastedad del vacío que la rodeaba como un lienzo en blanco esperando ser llenado con su esplendor. Es entonces que sentada en el Trono Dorado de Khyrsos, la Primera Estrella, su dominio; decidió dar origen a sus primogénitos. Así nacieron Gaia y Hæphistos, quienes encarnarían su legado y sus deseos.</p><p><br></p><p>El primero de sus hijos fue Gaia, la Diosa de las Montañas. Thæia modeló a Gaia con la firmeza de la roca y la fertilidad de la tierra. Ella recibió el dominio sobre Ouræ, el mundo mortal, un lugar lleno de vida y constante cambio.</p><p><br></p><p>El segundo hijo de Thæia fue Hæphistos, el Dios de la Metalurgia. Forjado del fuego y el metal, Hæphistos se destacó por su habilidad inigualable en la creación y la transformación. A él, Thæia le otorgó el don de la maestría sobre los minerales y la forja, convirtiéndolo en el patrono de los enanos, una raza de artesanos y mineros.</p><p><br></p><p><em>PD: Estoy terminando de pasar esta ultima religion grande en limpio, paciencia 🙏. Pero con esto ya estarian el 100% de las religiones grandes!<span class="ql-cursor">﻿</span></em></p>', '0c12d0a6-9f25-4d34-a65f-3c37d904974e', '2025-08-31 15:50:42.274762', '2025-08-31 15:54:21.964');

